const body = $json.body || $json;
const folder = String(body['Folder Path'] || body.folderPath || '').trim();
const postTitle = String(body['Post Title'] || body.postTitle || '').trim();
const postDescription = String(body['Post Description'] || body.postDescription || '').trim();
const channelTitle = String(body['Channel Title (Optional)'] || body.channelTitle || '').trim();
if (!folder) throw new Error('Folder Path is required');
if (!postTitle) throw new Error('Post Title is required');
return [{ folder, postTitle, postDescription, channelTitle }];

const raw = $json.stdout || '';
const data = JSON.parse(raw);
if (data.error) throw new Error(data.error);
return [{ ...data }];

const input = $input.first().json;
const snoteLink = input.url || input.link || input.data?.url || input.data?.link || input.postUrl || '';
if (!snoteLink) throw new Error('Snote response missing article URL');
const endpoint = ($env.SHORTENER_API_URL || '').trim();
const apiKey = ($env.SHORTENER_API_KEY || '').trim();
const timeout = Number($env.SHORTENER_TIMEOUT_MS || 15000);
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
async function shorten(longUrl) {
  if (!endpoint) return longUrl;
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: endpoint,
      timeout,
      headers: {
        Authorization: apiKey ? `Bearer ${apiKey}` : undefined,
        'Content-Type': 'application/json'
      },
      body: { longUrl },
      json: true
    });
    return res.shortUrl || res.short_url || res.link || res.url || longUrl;
  } catch {
    return longUrl;
  }
}
const links = [];
for (let i = 0; i < 3; i++) {
  links.push(await shorten.call(this, snoteLink));
  if (i < 2) await sleep(1200);
}
return [{ ...$json, snoteLink, shortLinks: links }];

const links = $json.shortLinks || [];
const l1 = links[0] || $json.snoteLink;
const l2 = links[1] || $json.snoteLink;
const l3 = links[2] || $json.snoteLink;
const thumbLinks = ($json.thumbnails || []).map((t) => t.messageLink);
const body = [
  `*${$json.postTitle || 'Movie moi'}*`,
  $json.postDescription || '',
  '',
  `Nguon Telegram: ${$json.channelTitle || ''} (${$json.channelId || ''})`,
  `Video da upload: ${$json.videoCount || 0}`,
  '',
  `[Link 1](${l1})`,
  `[Link 2](${l2})`,
  `[Link 3](${l3})`,
  '',
  'Thumbnails:',
  ...thumbLinks
].filter(Boolean).join('\n');
return [{ ...$json, publishText: body, discordText: body.replace(/\*/g, '**') }];
